// n8n Webhook 一般输入是 { headers, params, query, body, ... }
const root = $json || {};

// 1) 拿到 body（回调内容）
const body = (root.body && typeof root.body === 'object') ? root.body : root;

// 2) 新格式：body.context；旧格式：root.query（callbackUrl 参数）
const query = (root.query && typeof root.query === 'object') ? root.query : {};
const context = (body.context && typeof body.context === 'object') ? body.context : {};

// ---------- 统一取字段 ----------
const status = String(body.status ?? body.data?.status ?? '').toLowerCase();
const ok =
  status === 'success' ||
  status === 'completed' ||
  status === 'succeeded' ||
  String(body.data?.status ?? '').toLowerCase() === 'completed' ||
  String(body.data?.status ?? '').toLowerCase() === 'success';

const taskId =
  body.task_id ||
  body.taskId ||
  body.data?.id ||
  body.data?.taskId ||
  null;

let resultUrl =
  body.video_url ||
  body.data?.video_url ||
  body.data?.result_url ||
  null;

if (!resultUrl && body.data && typeof body.data.resultJson === 'string') {
  try {
    const parsed = JSON.parse(body.data.resultJson);
    if (Array.isArray(parsed.resultUrls) && parsed.resultUrls[0]) {
      resultUrl = parsed.resultUrls[0];
    }
  } catch (e) {}
}

const failMsg =
  body.failMsg ||
  body.data?.failMsg ||
  body.error?.message ||
  body.error_message ||
  body.message ||
  body.msg ||
  '';

const msg = ok ? 'success' : (failMsg || 'failed');

const pick = (...args) => {
  for (const v of args) {
    if (v != null && String(v).trim() !== '') return v;
  }
  return null;
};

return {
  json: {
    code: ok ? 200 : 500,
    codeStr: ok ? '200' : '500',
    msg,
    status: body.status ?? body.data?.status ?? null,
    taskId,
    resultUrl,
    failMsg,

    // web 字段（从 context 取，兼容 query）
    replication_id: pick(context.replication_id, context.record_id, query.replication_id, query.record_id),
    callback_url:   pick(context.callback_url,   query.callback_url),
    api_key:        pick(context.api_key,         query.api_key),
    workflow_id_for_credits: pick(context.workflow_id_for_credits, query.workflow_id_for_credits),

    // 保留飞书字段（兼容旧 Feishu 调用，web 场景为空）
    record_id:            pick(context.record_id,            query.record_id),
    app_token:            pick(context.app_token,            query.app_token),
    table_id:             pick(context.table_id,             query.table_id),
    out_app_token:        pick(context.out_app_token,        query.out_app_token),
    out_table_id:         pick(context.out_table_id,         query.out_table_id),
    tenant_access_token:  pick(context.tenant_access_token,  query.tenant_access_token),

    debug_raw_keys: Object.keys(body || {})
  }
};

const taskId = $json.taskId || `t${Date.now()}`;
return {
  json: {
    ...$json,
    taskId,
    ff_inPath: `/tmp/${taskId}.mp4`,
    ff_outPath: `/tmp/${taskId}_drop1.mp4`,
    ff_outFileName: `sora_video_${taskId}_drop1.mp4`,
  },
  binary: $binary,
};

const item = $input.item;
const base = item.json;

return {
  json: {
    taskId: base.taskId,
    record_id: base.record_id,
    app_token: base.app_token,
    table_id: base.table_id,
    tenant_access_token: base.tenant_access_token,
    api_key: base.api_key,
    workflow_id_for_credits: base.workflow_id_for_credits,
    fileName: `sora_video_${base.taskId}.mp4`
  },
  binary: item.binary
};

const keyRaw = $json.name || $json.objectKey || '';
const key = String(keyRaw).replace(/^\/+/, '');

const cdnHost = 'https://oss.flowonn.com';
const publicUrl = `${cdnHost}/${encodeURI(key)}`;

return {
  json: {
    publicUrl,
    record_id: $json.record_id,
    app_token: $json.app_token,
    table_id: $json.table_id,
    tenant_access_token: $json.tenant_access_token,
    api_key: $json.api_key,
    workflow_id_for_credits: $json.workflow_id_for_credits
  }
};

const ctx = $('解析回调+上下文').item.json || {};
const publicUrl = $json.publicUrl || '';
return {
  json: {
    id: ctx.replication_id,
    replication_id: ctx.replication_id || '',
    callback_url: ctx.callback_url || '',
    api_key: ctx.api_key || '',
    workflow_id_for_credits: ctx.workflow_id_for_credits || '',
    videoUrl: publicUrl,
    taskId: ctx.taskId || ''
  }
};

function safeTmpMp4(p, name) {
  if (!p) return null;
  if (typeof p !== 'string') throw new Error(`${name} 不是字符串`);
  if (!p.startsWith('/tmp/')) throw new Error(`${name} 非 /tmp 路径，拒绝删除：${p}`);
  if (!p.endsWith('.mp4')) throw new Error(`${name} 非 mp4，拒绝删除：${p}`);
  if (p.includes('..')) throw new Error(`${name} 包含 ..，拒绝删除：${p}`);
  return p;
}

const inPath = safeTmpMp4($json.ff_inPath, 'ff_inPath');
const outPath = safeTmpMp4($json.ff_outPath, 'ff_outPath');

const paths = [inPath, outPath].filter(Boolean);
const quoted = paths.map(p => `"${p.replace(/"/g, '\\"')}"`).join(' ');
const cleanup_cmd = paths.length
  ? `rm -f ${quoted} || true`
  : `echo "no tmp files to delete"`;

return {
  json: { ...$json, cleanup_cmd, cleanup_paths: paths },
  binary: $binary
};
